function frames(dir,pre,a,b){const r=[];for(let i=a;i<=b;i++){const im=new Image();im.onerror=()=>{im.broken=true;};const _k=(dir+'/'+pre+pad(i)+'.png').replace('../','');im.src=EMB[_k]||encodeURI(dir+'/'+pre+pad(i)+'.png');r.push(im);}return r;}
