function drawSprite(fr,x,y,h,flip,t){
 if(!fr||!fr.length)return false;
 const img=fr[Math.floor(t*9)%fr.length];
 // ИСПРАВЛЕНО: добавлена проверка !img.naturalHeight.
 // Раньше проверялся только naturalWidth, но на некоторых браузерах/мобильных
 // картинка complete=true, но naturalHeight ещё 0 → деление на ноль → w=Infinity
 // → ctx.drawImage с Infinity размерами бросал исключение → draw() обрывался
 // → моделька игрока исчезала. С проверкой naturalHeight мы возвращаем false
 // и срабатывает fallback: ctx.arc(px,py,P.r,...) — рисуется кружок-заглушка.
 if(!img||!img.complete||img.broken||!img.naturalWidth||!img.naturalHeight)return false;
 const w=h*img.naturalWidth/img.naturalHeight;
 ctx.save();ctx.translate(x,y);if(flip)ctx.scale(-1,1);ctx.drawImage(img,-w/2,-h*0.82,w,h);ctx.restore();return true;
}
function shadow(x,y,w){ctx.save();ctx.globalAlpha=.42;ctx.fillStyle='#000';ctx.beginPath();ctx.ellipse(x,y,w,w*0.34,0,0,7);ctx.fill();ctx.globalAlpha=.22;ctx.beginPath();ctx.ellipse(x,y,w*1.35,w*0.46,0,0,7);ctx.fill();ctx.restore();}

// ============================================================
//  OBJECT POOLING
// ============================================================
// ЗАЩИТА ОТ ПЕРЕБОРА: каждый poolGet/spawn тратит O(n) на подсчёт живых объектов
// в массиве (for...of с alive). На мобильном после 10 минут в массиве POOL.gems
// может быть 80 мёртвых объектов, и каждый spawnGem проходит их ВСЕ.
// Решение: держим отдельные activeX массивы, в которых только живые объекты.
// При poolGet/poolRelease — push/splice O(1).
// Циклы в draw() и update() идут по activeX, что в среднем в 5-10 раз быстрее.
const POOL={particles:[],dmgTexts:[],gems:[],flashes:[]};
const ACTIVE={particles:[],dmgTexts:[],gems:[],flashes:[]};
function poolGet(arr,reset){
 // ИСПРАВЛЕНО: отделено создание/поиск объекта от reset().
 // Раньше если reset() бросал исключение, состояние пула ломалось:
 // объект уже push'нут, но не инициализирован. Теперь сначала находим
 // или создаём объект, потом зовём reset — если он бросит, объект остаётся
 // в консистентном состоянии {alive:false}.
 let o=null;
 for(let i=arr.length-1;i>=0;i--){
  if(!arr[i].alive){o=arr[i];break;}
 }
 if(!o){o={alive:false};arr.push(o);}
 reset(o);
 o.alive=true;
 // Добавляем в active-список соответствующего пула
 const name=arr===POOL.particles?'particles':arr===POOL.dmgTexts?'dmgTexts':arr===POOL.gems?'gems':'flashes';
 ACTIVE[name].push(o);
 return o;
}
function poolRelease(arr,o){
 o.alive=false;
 const name=arr===POOL.particles?'particles':arr===POOL.dmgTexts?'dmgTexts':arr===POOL.gems?'gems':'flashes';
 const list=ACTIVE[name];
 const idx=list.indexOf(o);
 if(idx>=0)list.splice(idx,1);
}
function resetParticle(p){p.life=p.max=rnd(.25,.75);p.x=p.y=0;p.vx=p.vy=0;p.g=0;p.c='#fff';p.blood=0;}
function resetDmg(t){t.t=0.5;t.x=t.y=0;t.v=0;t.tag='phys';t.color='#fff';t.crit=false;}
function resetGem(g){g.x=g.y=0;g.v=1;g.col='#5adcff';g.vx=g.vy=0;g.pop=0;g.ms=0;g.dead=false;}
function resetFlash(f){f.t=f.max=0.16;f.x=f.y=0;f.big=0;f.color='#ffe6a0';}
const MAX_GEMS=80;
function spawnGem(x,y,v,col,vx,vy){
 if(ACTIVE.gems.length>=MAX_GEMS)return null;
 const g=poolGet(POOL.gems,resetGem);
 g.x=x;g.y=y;g.v=v;g.col=col;g.vx=vx||0;g.vy=vy||0;g.pop=0;g.ms=0;g.dead=false;
 return g;
}
const MAX_PARTICLES=200;
const MAX_FLASHES=30;
const MAX_DMG_TEXTS=30;
function spawnParticle(x,y,vx,vy,life,col,gravity,blood){
 if(ACTIVE.particles.length>=MAX_PARTICLES)return null;
 const p=poolGet(POOL.particles,resetParticle);
 p.x=x;p.y=y;p.vx=vx;p.vy=vy;p.life=life;p.max=life;p.c=col;p.g=gravity||0;p.blood=blood||0;
 return p;
}
function spawnDmgText(x,y,v,tag,crit){
 if(ACTIVE.dmgTexts.length>=MAX_DMG_TEXTS)return null;
 const t=poolGet(POOL.dmgTexts,resetDmg);t.x=x;t.y=y;t.v=v;t.tag=tag;const colMap={phys:'#fff',elec:'#8fd0ff',pois:'#9ac06a',frost:'#bfe0ff',void:'#b478ff'};t.color=colMap[tag]||'#fff';t.crit=crit;return t;
}
function spawnFlash(x,y,big,color){
 if(ACTIVE.flashes.length>=MAX_FLASHES)return null;
 const f=poolGet(POOL.flashes,resetFlash);f.x=x;f.y=y;f.big=big?1:0;f.t=big?0.24:0.16;f.max=f.t;f.color=color||'#ffe6a0';return f;
}

// ============================================================
//  SPATIAL HASH
// ============================================================
const CELL=160;
let grid=new Map();
function buildGrid(){grid.clear();for(const e of enemies){const cx=Math.floor(e.x/CELL),cy=Math.floor(e.y/CELL);const k=cx+','+cy;let arr=grid.get(k);if(!arr){arr=[];grid.set(k,arr);}arr.push(e);}}
// Быстрый поиск ближайших врагов через spatial hash (используется в doSword/doBolt/useSpecial)
function enemiesNear(x,y,r){
 const out=[];const r2=r*r;const minCx=Math.floor((x-r)/CELL),maxCx=Math.floor((x+r)/CELL);
 const minCy=Math.floor((y-r)/CELL),maxCy=Math.floor((y+r)/CELL);
 for(let cx=minCx;cx<=maxCx;cx++)for(let cy=minCy;cy<=maxCy;cy++){
  const arr=grid.get(cx+','+cy);if(!arr)continue;
  for(const e of arr)if(dist2(e.x-x,e.y-y)<=r2)out.push(e);
 }
 return out;
}

// ============================================================
//  ТУМАН ВОЙНЫ
// ============================================================
const EXPLORED_CELL=180;
let explored=new Set();
function markExplored(x,y){const cx=Math.floor(x/EXPLORED_CELL),cy=Math.floor(y/EXPLORED_CELL);for(let dx=-1;dx<=1;dx++)for(let dy=-1;dy<=1;dy++)explored.add((cx+dx)+','+(cy+dy));}
function isExplored(x,y){return !warpOn||explored.has(Math.floor(x/EXPLORED_CELL)+','+Math.floor(y/EXPLORED_CELL));}

