const TREE={
 power:{name:'⚔ Сила',nodes:[
  {id:'pw1',name:'+12% урон',cost:50,max:5,f:(l)=>P.dmgMul*=1+0.12*l,stat:'dmg'},
  // БЫЛО: +0.15 (игнорировало l) → на 2 уровне то же что на 1. Теперь +0.15*l.
  {id:'pw2',name:'+15% крит',cost:80,max:3,f:(l)=>P.crit=(P.crit||0)+0.15*l,stat:'crit'},
  // БЫЛО: *=1.25 (константа) → мультипликативно работало, но с неверной кривой
  // (множитель 1.25 каждый раз вместо +0.25*l). Теперь аддитивно: +0.25*l.
  {id:'pw3',name:'+25% боссам',cost:120,max:3,f:(l)=>P.bossMul=(P.bossMul||1)+0.25*l,stat:'boss'},
 ]},
 guard:{name:'🛡 Защита',nodes:[
  // БЫЛО: +=25 (константа) → 5 уровней давали только 25 HP. Теперь +=25*l.
  {id:'gd1',name:'+25 макс. HP',cost:50,max:5,f:(l)=>{P.maxhp+=25*l;P.hp=P.maxhp;},stat:'hp'},
  // БЫЛО: +0.3 (константа) → все 3 уровня давали те же 0.3 регена. Теперь +0.3*l.
  {id:'gd2',name:'+0.3 реген/с',cost:100,max:3,f:(l)=>P.regen=(P.regen||0)+0.3*l,stat:'regen'},
  {id:'gd3',name:'+15% броня',cost:80,max:3,f:(l)=>P.armor=(P.armor||0)+0.15*l,stat:'armor'},
 ]},
 speed:{name:'⚡ Скорость',nodes:[
  {id:'sp1',name:'+12% бег',cost:50,max:5,f:(l)=>P.spd*=1+0.12*l,stat:'spd'},
  // БЫЛО: *=1.18 (константа) → все 3 уровня давали один и тот же буст.
  // Теперь *=1+0.18*l — кривая как у pw1/sp1.
  {id:'sp2',name:'+18% атака',cost:80,max:3,f:(l)=>P.rateMul*=1+0.18*l,stat:'rate'},
  {id:'sp3',name:'+25% подбор',cost:60,max:3,f:(l)=>P.pickup*=1+0.25*l,stat:'pickup'},
 ]},
 fate:{name:'🌟 Судьба',nodes:[
  // БЫЛО: *=1.3 (константа) → каждый уровень давал 30% сверху, что слишком сильно.
  // Теперь +0.3*l — аддитивно, мягче.
  {id:'ft1',name:'+30% XP',cost:60,max:4,f:(l)=>P.xpMul=(P.xpMul||1)+0.3*l,stat:'xp'},
  {id:'ft2',name:'+20% золото',cost:60,max:4,f:(l)=>P.goldMul=(P.goldMul||1)+0.2*l,stat:'gold'},
  // БЫЛО: +1 (константа) → 2 уровня давали 1 слот вместо 2. Теперь +l.
  {id:'ft3',name:'+1 слот реликвий',cost:200,max:2,f:(l)=>P.maxRelics=(P.maxRelics||3)+l,stat:'relicslot'},
 ]}
};
function openTree(){
 paused=true;
 document.getElementById('treeov').style.display='flex';
 const row=document.getElementById('treerow');row.innerHTML='';
 for(const k in TREE){
  const branch=TREE[k];
  const bdiv=document.createElement('div');
  bdiv.style.cssText='background:rgba(20,24,16,.8);border:1px solid #5a604a;border-radius:6px;padding:8px;min-width:140px';
  bdiv.innerHTML=`<h3 style="color:#ffcf6a;margin:0 0 6px;font-size:13px">${branch.name}</h3>`;
  branch.nodes.forEach(n=>{
   const lvl=tree[n.id]||0;
   const maxed=lvl>=n.max;
   const cost=n.cost*(lvl+1);
   const can=!maxed&&metaGold>=cost;
   const d=document.createElement('div');
   d.className='treenode'+(maxed?' maxed':(can?' can':' locked'));
   d.innerHTML=`<h4>${n.name}</h4><p class="lvl">Ур. ${lvl}/${n.max}</p><div class="cost">${maxed?'МАКС':'◆ '+cost}</div>`;
   d.onclick=()=>{if(maxed||!can)return;metaGold-=cost;tree[n.id]=lvl+1;LS.set('cl_gold',metaGold);LS.set('cl_tree',JSON.stringify(tree));if(lvl+1>=n.max){achData.progress.treeMax=(achData.progress.treeMax||0)+1;LS.set('cl_ach',JSON.stringify(achData));}sfxUpgrade();openTree();};
   bdiv.appendChild(d);
  });
  row.appendChild(bdiv);
 }
 document.getElementById('treecost').textContent=`Золото Заставы: ${metaGold} ◆`;
}
document.getElementById('btnTree').onclick=openTree;
document.getElementById('btnTreeClose').onclick=()=>{document.getElementById('treeov').style.display='none';paused=false;};
function applyTree(){
 for(const k in TREE)for(const n of TREE[k].nodes){
  const lvl=tree[n.id]||0;
  if(lvl>0)n.f(lvl);
 }
}

// ============================================================
//  СПАВН (ЗА пределами экрана, не из ниоткуда)
//  Камера: cam.x/y = ЛЕВЫЙ-ВЕРХНИЙ угол экрана. Спавн ведём от ЦЕНТРА камеры
//  (cam.x + W/2, cam.y + H/2), иначе при упоре камеры в край мира
//  враг появлялся в центре экрана, потому что P.x уже уехал, а cam.x — нет.
// ============================================================
function spawn(forceDistant){
 const step=Math.floor(time/90);
 const hpMul=(1+0.10*step)*(isFinite(diffMul)?diffMul:1);
 // Истинный центр видимого экрана
 const cx=cam.x+W/2;
 const cy=cam.y+H/2;
 // Распределение типов. seedRandom для Daily → репродуцируемая последовательность мобов.
 const roll=seedRandom();
 let type='rootling';
 if(time>240&&roll<0.12)type='troll';
 else if(time>120&&roll<0.22)type='shaman';
 else if(time>60&&roll<0.50)type='imp';
 else if(time>120&&roll<0.62)type='wraith';
 const e=ETYPES[type];
 if(!e)return;
 let sx=0,sy=0,valid=false;
 // До 10 попыток найти точку: внутри мира [0..WORLD] И снаружи прямоугольника камеры.
 for(let i=0;i<10;i++){
  const a=rnd(0,Math.PI*2);
  // Базовый радиус: половина большей стороны экрана + запас 100-250
  let dist=Math.max(W,H)/2+rnd(100,250);
  // forceDistant — добавить ещё 400-700, чтобы не лезли в плотную зону
  if(forceDistant)dist+=rnd(400,700);
  sx=cx+Math.cos(a)*dist;
  sy=cy+Math.sin(a)*dist;
  // 1) внутри мира
  if(sx>=0&&sx<=WORLD&&sy>=0&&sy<=WORLD){
   // 2) СТРОГО за пределами прямоугольника камеры (с запасом 50px)
   if(sx<cam.x-50||sx>cam.x+W+50||sy<cam.y-50||sy>cam.y+H+50){
    valid=true;break;
   }
  }
 }
 // Если игрок зажат в углу карты и свободного места за экраном нет — отменяем спавн
 if(!valid)return;
 const safeHp=isFinite(e.hp*hpMul)&&e.hp*hpMul>0?e.hp*hpMul:5;
 enemies.push({...e,x:sx,y:sy,hp:safeHp,maxhp:safeHp,type,flash:0,kx:0,ky:0,at:0,slow:1,hitT:0,wasInRange:false,boltT:0,frozen:0,poisoned:0,zigzag:rnd(0,6.28),zigzagT:0,ai:e.ai,dmgMod:e.dmgMod,fireT:0,spawnT:2.5,warnT:1.5});
}
function spawnElite(){
 // Спавн от ЦЕНТРА КАМЕРЫ (cam.x+W/2, cam.y+H/2), а не от P.x/P.y
 // Иначе при упоре камеры в край мира элита появится в центре экрана.
 // + защита clamp в пределы мира [0..WORLD]
 const cx=cam.x+W/2,cy=cam.y+H/2;
 const a=rnd(0,6.28),rad=Math.max(W,H)*0.85+200,b=ETYPES.troll;
 const minR=Math.max(W,H)*0.6+100;
 const minR2=minR*minR;
 let sx=cx+Math.cos(a)*rad,sy=cy+Math.sin(a)*rad;
 if(dist2(sx-cx,sy-cy)<minR2){const a2=Math.atan2(sy-cy,sx-cx);sx=cx+Math.cos(a2)*minR;sy=cy+Math.sin(a2)*minR;}
 // Защита от выхода за границы мира
 sx=clamp(sx,0,WORLD);sy=clamp(sy,0,WORLD);
 // hasRelic: флаг — даст реликвию ПОСЛЕ убийства, не на спавне
 enemies.push({...b,x:sx,y:sy,hp:b.hp*8*diffMul,maxhp:b.hp*8*diffMul,type:'troll',elite:true,drawH:b.drawH*1.3,at:0,flash:0,slow:1,kx:0,ky:0,hitT:0,wasInRange:false,boltT:0,frozen:0,poisoned:0,zigzag:a,zigzagT:0,ai:'tank',dmgMod:1.5,fireT:0,hasRelic:seedRandom()<(0.35+(P.luck||0))});
 log('⚠ Элитный тролль!', 'warn');
}
function spawnBoss(){
 // Та же логика — от центра камеры + clamp в мир.
 const cx=cam.x+W/2,cy=cam.y+H/2;
 const a=rnd(0,6.28),rad=Math.max(W,H)*0.85+200,b=ETYPES.troll;
 const minR=Math.max(W,H)*0.6+100;
 const minR2=minR*minR;
 let sx=cx+Math.cos(a)*rad,sy=cy+Math.sin(a)*rad;
 if(dist2(sx-cx,sy-cy)<minR2){const a2=Math.atan2(sy-cy,sx-cx);sx=cx+Math.cos(a2)*minR;sy=cy+Math.sin(a2)*minR;}
 sx=clamp(sx,0,WORLD);sy=clamp(sy,0,WORLD);
 bossE={...b,x:sx,y:sy,hp:2600*diffMul,maxhp:2600*diffMul,r:44,spd:34,dmg:22,type:'troll',boss:true,drawH:172,at:0,flash:0,slow:1,kx:0,ky:0,hitT:0,wasInRange:false,boltT:0,frozen:0,poisoned:0,slamT:3.5,phase:1,xp:0,ai:'tank',dmgMod:1.5,fireT:0};
 enemies.push(bossE);
 document.getElementById('bossbar').style.display='block';
 document.getElementById('bossname').textContent='КОРНЕВОЙ БЕРСЕРК';
 const intro=document.getElementById('bossintro');intro.classList.add('show');sfxBoss();setTimeout(()=>intro.classList.remove('show'),2500);
}
function addRelic(r){
 const maxSlots=P.maxRelics||3;
 if(relics.length>=maxSlots)return;
 relics.push(r);
 // ДИНАМИЧЕСКИЙ СЛОТ: в HTML только rs0/rs1/rs2, но узел древа ft3 даёт 4-й слот.
 // Без создания элемента 4-я реликвия не появится, обесценивая покупку.
 const slotId='rs'+(relics.length-1);
 let slot=document.getElementById(slotId);
 if(!slot){
  slot=document.createElement('div');
  slot.className='relic-slot';
  slot.id=slotId;
  const container=document.getElementById('relics');
  if(container)container.appendChild(slot);
 }
 if(slot){slot.classList.add('full');slot.textContent=r.icon;slot.title=r.name;}
 r.apply();
 log(`💎 ${r.name}`, 'gold');
 sfxUpgrade();
}
function levelUp(){
 sfxLevel();level++;xp-=xpNext;xpNext=Math.floor(5+level*3+Math.pow(level,1.5));
 paused=true;showCards();
 // ИСПРАВЛЕНО: ищем оружие по ID, а не по индексу weapons[0].
 // Раньше меч был жёстко на индексе [0], что ломалось у Шамана (стартует с молнией
 // из passive, и его оружия = [sword, bolt], а мы хотим искать по id).
 const sW=weapons.find(w=>w.id==='sword');
 if(swordLvl>=5&&sW&&!sW.evo){sW.evo=true;runStats.swordEvo=true;log('⚔ Рагнарёк пробуждается!','evo');sfxEvo();}
 const bW=weapons.find(w=>w.id==='bolt');
 if(boltLvl>=5&&bW&&!bW.evo){bW.evo=true;runStats.boltEvo=true;log('⚡ Громобой нисходит!','evo');sfxEvo();}
 if(level%3===0)spawnAnomaly();
 if(level%5===0&&seedRandom()<0.5)spawnElite();
}

// ============================================================
//  АНОМАЛИИ
// ============================================================
function spawnAnomaly(){
 // ЗАЩИТА: clamp в границы мира [16..2384] (16 = половина иконки 32px).
 // Иначе у края карты сундук появлялся за стеной, и игрок видел иконку,
 // но не мог её подобрать (упирался в clamp на P.x).
 const ang=rnd(0,Math.PI*2),dist_=rnd(200,360);
 const x=clamp(P.x+Math.cos(ang)*dist_, 16, WORLD-16);
 const y=clamp(P.y+Math.sin(ang)*dist_, 16, WORLD-16);
 const types=['chest','altar','vein'];
 const type=types[Math.floor(seedRandom()*types.length)];
 anomalies.push({x,y,type,born:time});
 const el=document.createElement('div');
 el.className='anomaly';
 el.textContent=type==='chest'?'◆':type==='altar'?'✦':'▲';
 el.dataset.x=x;el.dataset.y=y;el.dataset.type=type;
 document.body.appendChild(el);
 anomalies[anomalies.length-1].domEl=el;
 log(type==='chest'?'Найден сундук!':type==='altar'?'Найден алтарь!':'Золотая жила!','gold');
 sfxAnomaly();
}
function tryClaimAnomaly(a){
 if(a.claimed)return;
 if(dist2(P.x-a.x,P.y-a.y)>900)return; // 30^2
 a.claimed=true;
 if(a.domEl)a.domEl.remove();
 if(a.type==='chest'){gold+=50;log('+50 ◆','gold');sfxPick();}
 else if(a.type==='altar'){showCardsFree();log('Алтарь дарует силу!','gold');}
 else if(a.type==='vein'){gold+=200;log('+200 ◆','gold');sfxPick();}
 // ИСПРАВЛЕНО: splice удалён, чтобы не ломать for...of в update().
 // Раньше удаление элемента по индексу во время for...of смещало итератор
 // и приводило к пропуску соседних аномалий. Теперь они остаются в массиве
 // с флагом claimed=true, и update() отфильтрует их одним .filter в конце.
}
function showCardsFree(){
 paused=true;
 const pool=[...CARD_POOL];
 const opts=[];for(let i=0;i<3&&pool.length;i++)opts.push(pool.splice(Math.floor(Math.random()*pool.length),1)[0]);
 const row=document.getElementById('cardrow');row.innerHTML='';
 opts.forEach(o=>{const d=document.createElement('div');d.className='card';d.innerHTML=`<h3>${o.t}</h3><p>${o.d}</p><span class="tag">дар</span>`;d.onclick=()=>{o.f();closeCards();};row.appendChild(d);});
 document.getElementById('cardbtns').style.display='none';
 document.getElementById('cards').style.display='flex';
}
function log(text,cls){
 const el=document.createElement('div');el.className='logitem'+(cls?' '+cls:'');el.textContent=text;
 const log=document.getElementById('log');
 log.appendChild(el);
 while(log.children.length>3)log.firstChild.remove();
 setTimeout(()=>el.remove(),4100);
}

// ============================================================
//  СПЕЦАТАКА
// ============================================================
let specialMax=1,specialCharge=0;
function useSpecial(){
 if(paused||over||runEnded)return;
 if(specialCharge<specialMax)return;
 specialCharge--;
 const r=180;
 shake=12;sfxEvo();
 // spatial hash для ближайших
 const r2=r*r;
 const candidates=enemiesNear(P.x,P.y,r);
 for(const e of candidates){
  const dmg=100*P.dmgMul;
  hitEnemy(e,dmg,'void',true);
  e.kx=(e.kx||0)+(e.x-P.x)/r*500;
  e.ky=(e.ky||0)+(e.y-P.y)/r*500;
 }
 spawnFlash(P.x,P.y,1,'#b478ff');
 for(let i=0;i<40;i++){const a=randomVisual()*6.28,sp=rnd(100,300);if(!spawnParticle(P.x,P.y,Math.cos(a)*sp,Math.sin(a)*sp,rnd(.4,.8),'#b478ff',-200,0))break;}
 // ИСПРАВЛЕНО: УДАЛЕНО `P.rateMul*=1.5`. Бафф скорости атаки от спецатаки
 // теперь работает ТОЛЬКО через P.specialRate (временный множитель ×1.5 на 5 сек).
 // Раньше rateMul *= 1.5 применялся при первом использовании спецатаки
 // (с защитой if(P.specialBuffT<=0) от стека), НО rateMul НАВСЕГДА становился ×1.5
 // после первого использования — снятие specialRate обратно rateMul не возвращало.
 // Теперь rateMul хранит ТОЛЬКО постоянные апгрейды (карточки/древо/класс).
 P.specialRate=1.5;
 P.specialBuffT=5; // 5 секунд игрового времени
}

// ============================================================
//  КАРТОЧКИ АПГРЕЙДОВ
// ============================================================
